#include<bits/stdc++.h>
using namespace std;

int n;
string a;
int sum, maxs = 0;

int main() {
	cin >> n >> a;
	for (int i = 0; i <= n; i++) {
		sum = 0;
		if (i != n) {
			if (a[i] == 'V') {
				a[i] = 'K';
			} else {
				a[i] = 'V';
			}
		}
		for (int i = 1; i < n; i++) {
			if (a[i] == 'K' && a[i - 1] == 'V') {
				sum++;
			}
		}
		maxs = max(sum, maxs);
		if (i != n) {
			if (a[i] == 'V') {
				a[i] = 'K';
			} else {
				a[i] = 'V';
			}
		}
	}
	cout << maxs;
	return 0;
}
